<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Marketing - Campañas</title><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link rel="stylesheet" href="../../assets/framework/framework.css"><script src="../../assets/framework/framework.js" defer></script><link rel="stylesheet" href="marketing_styles.css"></head><body><div class="layout"><?php require __DIR__ . '/../../partials/marketing_nav.php'; ?><main class="main"><header class="navbar"><div class="navbar-left"><button class="btn-icon" onclick="toggleSidebar()"><span class="material-icons">menu</span></button><div class="navbar-title">Campañas internas</div></div><?= renderBotonPerfil($perfil['avatar_path'] ?? ($_SESSION['avatar_path'] ?? null)) ?></header><section class="content page-stack"><?php if (($flash['message'] ?? '') !== ''): ?><div class="flash <?= mh($flash['type']) ?>"><?= mh($flash['message']) ?></div><?php endif; ?>
<div class="plan-grid"><form class="marketing-card" method="post"><input type="hidden" name="action" value="save_campaign"><h2>Crear campaña interna</h2><div class="form-grid"><select name="subscription_id" required><option value="">Suscripcion</option><?php foreach($suscripciones as $s): ?><option value="<?= (int)$s['id'] ?>"><?= mh(($s['user_label'] ?? '') . ' - ' . ($s['plan_name'] ?? '') . ' - ' . ($s['status'] ?? '')) ?></option><?php endforeach; ?></select><input name="campaign_name" placeholder="Nombre interno" required><select name="channel"><option value="meta_ads">Meta Ads</option><option value="instagram_organic">Instagram organic</option><option value="google_ads">Google Ads</option><option value="email">Email</option><option value="whatsapp">Whatsapp</option><option value="linkedin">LinkedIn</option><option value="other">Otro</option></select><select name="objective"><option>MENSAJES</option><option>LEADS</option><option>TRAFICO</option><option>VENTAS</option><option>REMARKETING</option><option>ALCANCE</option><option>OTRO</option></select><input type="date" name="start_date"><input type="date" name="end_date"><input name="budget" placeholder="Presupuesto"><select name="status"><option value="draft">Borrador</option><option value="active">Activa</option><option value="paused">Pausada</option><option value="completed">Completada</option><option value="cancelled">Cancelada</option></select><input name="external_campaign_name" placeholder="Nombre externo si existe"></div><button class="btn btn-aceptar" type="submit">Crear campaña</button></form>
<form class="marketing-card" method="post"><input type="hidden" name="action" value="save_client_code"><h2>Codigo de cliente</h2><div class="form-grid"><select name="user_auth_id" required><option value="">Cliente/emprendedor</option><?php foreach($usuariosFinales as $u): ?><option value="<?= (int)$u['id'] ?>"><?= mh($u['display_name'] ?? '') ?></option><?php endforeach; ?></select><input name="display_name" placeholder="Nombre visible"><input name="client_code" placeholder="ACME, NOVA, CLI001" required></div><button class="btn btn-aceptar" type="submit">Guardar codigo</button></form></div>
<div class="marketing-card"><h2>Campañas</h2><div class="table-wrap"><table class="marketing-table"><thead><tr><th>Cliente</th><th>Campaña</th><th>Nombre Meta recomendado</th><th>Canal</th><th>Estado</th><th>Metricas comerciales</th></tr></thead><tbody><?php foreach($campanias as $c): ?><tr><td><?= mh($c['user_label'] ?? '') ?></td><td><?= mh($c['campaign_name'] ?? '') ?></td><td><span class="copy-code" id="code-<?= (int)$c['id'] ?>"><?= mh($c['recommended_meta_campaign_name'] ?? '') ?></span><button class="btn" type="button" onclick="navigator.clipboard.writeText(document.getElementById('code-<?= (int)$c['id'] ?>').textContent)">Copiar</button></td><td><?= mh($c['channel'] ?? '') ?></td><td><?= statusLabel($c['status'] ?? '') ?></td><td><form method="post" class="form-grid"><input type="hidden" name="action" value="save_commercial_metrics"><input type="hidden" name="campaign_id" value="<?= (int)$c['id'] ?>"><input type="date" name="metric_period_start"><input type="date" name="metric_period_end"><input type="number" name="closed_clients" placeholder="Clientes cerrados"><input type="number" name="proposals_sent" placeholder="Propuestas"><input type="number" name="unsuccessful_contacts" placeholder="Contactos no exitosos"><input type="number" name="successful_contacts" placeholder="Contactos exitosos"><input type="number" name="meetings_scheduled" placeholder="Reuniones pactadas"><input type="number" name="meetings_completed" placeholder="Reuniones realizadas"><input name="quoted_amount" placeholder="Monto propuesto"><input name="closed_revenue" placeholder="Ventas cerradas"><textarea name="notes" placeholder="Notas"></textarea><button class="btn btn-aceptar" type="submit">Cargar</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php if(empty($campanias)): ?><div class="empty">No hay campañas internas.</div><?php endif; ?></div>
